import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import axios from 'axios';
import { FiPackage, FiMapPin, FiGlobe, FiCheck, FiArrowLeft } from 'react-icons/fi';

function SupplierDetail() {
  const { id } = useParams();
  const [supplier, setSupplier] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const res = await axios.get(`/api/suppliers/${id}`);
        setSupplier(res.data);
      } catch (err) {
        console.error('Error loading supplier', err);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [id]);

  if (loading) return <div className="loading">Loading...</div>;
  if (!supplier) return <div className="loading">Supplier not found.</div>;

  return (
    <div className="supplier-detail">
      <div className="container">
        <div className="supplier-header-card">
          <div className="supplier-avatar-lg">
            {supplier.name?.charAt(0)}
          </div>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '10px' }}>
              <h1>{supplier.name}</h1>
              {supplier.verified && (
                <span className="verified-badge" title="Verified Supplier">✓ Verified</span>
              )}
            </div>
            <p className="supplier-location">{supplier.location}</p>
            <p className="supplier-description">{supplier.description}</p>
            {supplier.website && (
              <a className="supplier-website" href={supplier.website} target="_blank" rel="noreferrer">
                Visit website
              </a>
            )}
          </div>
        </div>

        <div className="supplier-products">
          <h3>Products</h3>
          <div className="products-grid">
            {supplier.products.map((p) => (
              <Link key={p.id} to={`/products/${p.id}`} className="product-card">
                <div className="product-image">
                  {p.image_url ? (
                    <img src={p.image_url} alt={p.name} />
                  ) : (
                    <div className="product-placeholder">No Image</div>
                  )}
                </div>
                <div className="product-info">
                  <h4>{p.name}</h4>
                  <p className="product-price">
                    ₹{p.price?.toLocaleString() || 'Price on Request'}
                  </p>
                  <p className="product-category">{p.category_name}</p>
                </div>
              </Link>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

export default SupplierDetail;
